/// by [`RuntimeZC::run_inner`]. `fn(...) -> R` is `Copy +
/// Send + Sync`, which keeps the orchestration scaffold
/// generic without closure / `Fn`-bound complications.
type ActorLoopFn<S, R> = fn(
    Box<dyn ActorZC<S> + Send>,
    Receiver<SignalZC<S>>,
    Vec<Sender<SignalZC<S>>>,
